-- Source of truth for factor feature calculation definitions.
-- Reapply this file to refresh feature-level calculation metadata.

DROP TABLE IF EXISTS public.ticker_factor_feature_definitions;

CREATE TABLE public.ticker_factor_feature_definitions (
  id BIGSERIAL PRIMARY KEY,

  model_key TEXT NOT NULL,
  model_version TEXT NOT NULL,

  factor TEXT NOT NULL,
  axis TEXT NOT NULL,
  metric_key TEXT NOT NULL,
  feature_key TEXT NOT NULL,

  feature_label TEXT NOT NULL,
  feature_description TEXT,

  method_key TEXT NOT NULL,
  value_type TEXT NOT NULL,
  unit TEXT,
  period_type TEXT,

  source_loader_key TEXT,
  benchmark_loader_key TEXT,

  source_table TEXT,
  source_version TEXT,
  source_metric_key TEXT,
  source_column TEXT,
  process_key TEXT,

  benchmark_key TEXT,
  benchmark_keys JSONB NOT NULL DEFAULT '[]'::jsonb,

  lookback INTEGER,
  method_params JSONB NOT NULL DEFAULT '{}'::jsonb,
  source_payload JSONB NOT NULL DEFAULT '{}'::jsonb,
  definition_payload JSONB NOT NULL DEFAULT '{}'::jsonb,

  comparison BOOLEAN NOT NULL DEFAULT false,
  macro_contrast BOOLEAN NOT NULL DEFAULT false,
  is_vector_eligible BOOLEAN NOT NULL DEFAULT false,
  show_in_vector BOOLEAN NOT NULL DEFAULT false,

  display_order INTEGER NOT NULL DEFAULT 100,
  is_active BOOLEAN NOT NULL DEFAULT true,

  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),

  CONSTRAINT uq_tffd UNIQUE (
    model_key,
    model_version,
    factor,
    axis,
    metric_key,
    feature_key
  ),

  CONSTRAINT chk_tffd_benchmark_keys_array
  CHECK (jsonb_typeof(benchmark_keys) = 'array'),

  CONSTRAINT chk_tffd_method_params_object
  CHECK (jsonb_typeof(method_params) = 'object'),

  CONSTRAINT chk_tffd_source_payload_object
  CHECK (jsonb_typeof(source_payload) = 'object'),

  CONSTRAINT chk_tffd_definition_payload_object
  CHECK (jsonb_typeof(definition_payload) = 'object')
);

CREATE INDEX IF NOT EXISTS idx_tffd_active_lookup
ON public.ticker_factor_feature_definitions (
  factor,
  axis,
  is_active,
  display_order
);

CREATE INDEX IF NOT EXISTS idx_tffd_model_lookup
ON public.ticker_factor_feature_definitions (
  model_key,
  model_version,
  factor,
  axis
);

